#include<bits/stdc++.h>
using namespace std;
vector<pair<long long,long long>> mp[5050];
long long dis[5050],cnt[5050],n,m;
bool vis[5050];
bool spfa()
{
    memset(dis,-0x3f,sizeof(dis));
    dis[n+1]=0;
    stack<long long> q;
    q.push(n+1);
    while(!q.empty())
    {
        long long t=q.top();
        q.pop();
        vis[t]=0;
        for(auto i:mp[t])
        {
            long long v=i.first,val=i.second;
            if(dis[v]<dis[t]+val)
            {
                cnt[v]++;
                if(cnt[v]>n+5)
                {
                    return false;
                }
                dis[v]=dis[t]+val;
                if(!vis[v])
                {
                    vis[v]=1;
                    q.push(v);
                }
            }
        }
    }
    return true;
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        mp[n+1].push_back(make_pair(i,0));
    }
    for(long long i=1;i<=m;i++)
    {
        long long u,v,w;
        scanf("%lld%lld%lld",&u,&v,&w);
        mp[u].push_back(make_pair(v,-w));
    }
    if(spfa())
    {
        for(long long i=1;i<=n;i++)
        {
            printf("%lld ",dis[i]);
        }
    }
    else
    {
        printf("NO");
    }
    return 0;
}
